def audit_image_pipeline(tasks):
    rows = []
    for t in tasks:
        model = pick_image_model(t)
        rows.append({
            "task_id": t["task_id"],
            "model": model,
            "specialist_used": model in SPECIALISTS,
        })
    return rows

for row in audit_image_pipeline(tasks):
    print(f"{row['task_id']}: {row['model']:<18} specialist={row['specialist_used']}")

