PRICING = {
    "nano-banana":      0.039,
    "flux-1.1-pro":     0.04,
    "flux-pro-ultra":   0.06,
    "midjourney-v7":    0.10,
    "dall-e-3":         0.04,
    "ideogram-3":       0.0375,
    "gpt-image-1-mini": 0.005,
    "gpt-image-1":      0.042,
    "imagen-4":         0.04,
    "imagen-4-ultra":   0.06,
    "flux-kontext-pro": 0.04,
}

UPSCALE_COST = 0.06

PLATFORM_FORMATS = {
    "instagram": ["JPEG_1080"],
    "web":       ["WEBP_1920", "WEBP_400_thumb"],
    "email":     ["JPEG_600"],
    "tiktok":    ["JPEG_1080_vertical"],
}

briefs = [
    ("B1", {"channel": "web", "needs_text_in_image": True, "batch_count": 5, "budget_per_image": 0.10}),
    ("B2", {"channel": "instagram", "subjective_taste": True, "batch_count": 4, "budget_per_image": 0.15}),
    ("B3", {"channel": "tiktok", "batch_count": 50, "budget_per_image": 0.05}),
    ("B4", {"channel": "web", "photoreal_art_directed": True, "batch_count": 10, "needs_4k": True, "budget_per_image": 0.15}),
]

def pick_image_model(task):
    if task.get("budget_per_image", 1.0) < 0.02:
        return "gpt-image-1-mini"
    if task.get("needs_text_in_image"):
        return "ideogram-3"
    if task.get("needs_character_consistency"):
        return "flux-kontext-pro"
    if task.get("photoreal_art_directed"):
        return "flux-1.1-pro"
    if task.get("batch_count", 1) >= 10:
        return "nano-banana"
    if task.get("subjective_taste"):
        return "midjourney-v7"
    if task.get("instruction_heavy"):
        return "gpt-image-1"
    return "imagen-4"

def cost_for_batch(model, count, options=None):
    options = options or {}
    base = PRICING[model] * count
    if options.get("upscale"):
        base += UPSCALE_COST * count
    return round(base, 2)

def plan_shoot(brief):
    model = pick_image_model(brief)
    count = brief.get("batch_count", 1)
    options = {"upscale": brief.get("needs_4k", False)}
    total_cost = cost_for_batch(model, count, options)
    formats = PLATFORM_FORMATS.get(brief.get("channel", "web"), ["WEBP_1920"])
    return {
        "model": model,
        "count": count,
        "total_cost": total_cost,
        "formats": formats,
    }

for name, b in briefs:
    p = plan_shoot(b)
    print(f"{name}: model={p['model']:<18} count={p['count']:>3}  total=${p['total_cost']:>6.2f}  formats={p['formats']}")
